// Guard that the single-thread WASI loaders (`rolldown-binding.wasip1.*`,
// the flavor `@rolldown/browser` ships) are threadless end-to-end. The
// loaders are generated by @napi-rs/cli; a future cli bump or a wrong
// `hasThreads` resolution could silently reintroduce a Worker / shared memory
// / non-zero async work pool into the shipped browser artifact while CI stays
// green. This mirrors the napi-rs upstream guard
// (examples/custom-async-runtime/test.mjs) for rolldown's own loaders.

import * as fs from 'node:fs';
import * as path from 'node:path';
import { fileURLToPath } from 'node:url';

const REPO_ROOT = fileURLToPath(new URL('../../', import.meta.url));
const packageJson = JSON.parse(
  fs.readFileSync(path.join(REPO_ROOT, 'packages/rolldown/package.json'), 'utf8'),
);
const configuredInitialMemory =
  packageJson.napi?.wasm?.threadlessInitialMemory ?? packageJson.napi?.wasm?.initialMemory;
const configuredMaximumMemory = packageJson.napi?.wasm?.maximumMemory;
if (!Number.isInteger(configuredInitialMemory) || configuredInitialMemory < 1) {
  throw new TypeError('packages/rolldown/package.json must declare a positive WASI initialMemory');
}
if (
  !Number.isInteger(configuredMaximumMemory) ||
  configuredMaximumMemory < configuredInitialMemory ||
  configuredMaximumMemory > 65_536
) {
  throw new TypeError('packages/rolldown/package.json must declare a valid memory32 maximumMemory');
}
if (configuredInitialMemory > 1024) {
  throw new RangeError(
    `Threadless WASI initialMemory regressed above the measured 64 MiB budget: ${configuredInitialMemory} pages`,
  );
}

// The browser loader is the shipped browser artifact and the primary target;
// the node (.cjs) and deferred (workerd) loaders are checked too since the
// same build generates all three.
// Self-test / debugging: pass explicit loader paths as CLI args to point the
// guard at temporary copies (used to exercise the negative cases). Paths are
// resolved relative to the current working directory when not absolute.
const DEFAULT_LOADERS = [
  'packages/rolldown/src/rolldown-binding.wasip1-browser.js',
  'packages/rolldown/src/rolldown-binding.wasip1.cjs',
  'packages/rolldown/src/rolldown-binding.wasip1-deferred.js',
];
const THREADLESS_DECLARATION = 'packages/rolldown/src/rolldown-binding.wasip1-deferred.d.ts';
const argLoaders = process.argv.slice(2);
const LOADERS = argLoaders.length > 0 ? argLoaders : DEFAULT_LOADERS;
const resolveLoader = (rel) =>
  argLoaders.length > 0 ? path.resolve(process.cwd(), rel) : path.join(REPO_ROOT, rel);

// Markers that must NOT appear in a single-thread loader (threaded loaders add
// `new Worker(...)`, `onCreateWorker() {...}` and `shared: true`).
const FORBIDDEN = [/new Worker\b/, /onCreateWorker\b/, /shared:\s*true\b/];

// Strip comments so a commented `// asyncWorkPoolSize: 0` cannot satisfy the
// requirement and a commented `// new Worker(...)` cannot trip a false failure.
// We check only the EXECUTABLE source. The strip is intentionally conservative
// and dependency-free:
//   - block comments `/* ... */` are removed first;
//   - line comments are removed only when `//` starts a token (start-of-line or
//     after whitespace) so a `://` inside a string literal (e.g. a URL) is left
//     intact. The generated napi-rs loaders carry no `//`-in-string today; this
//     heuristic just keeps the guard from misfiring if one ever appears.
const stripComments = (source) =>
  source.replace(/\/\*[\s\S]*?\*\//g, '').replace(/(^|\s)\/\/[^\n]*/g, '$1');

const failures = [];
let importedMinimumMemory;

if (argLoaders.length === 0) {
  const bindingDeclarationPath = path.join(
    REPO_ROOT,
    'packages/rolldown/src/rolldown-binding.wasip1.d.cts',
  );
  const bindingDeclaration = fs.readFileSync(bindingDeclarationPath, 'utf8');
  for (const removedExport of [
    'cancelCurrentThreadRuntimeTaskDispatch',
    'driveCurrentThreadRuntimeTasks',
  ]) {
    if (bindingDeclaration.includes(removedExport)) {
      failures.push(
        `${path.relative(REPO_ROOT, bindingDeclarationPath)}: exposes removed CurrentThread task-host export ${removedExport}`,
      );
    }
  }
  for (const signature of [
    'export interface BindingHostRegistration {',
    'high: number',
    'low: number',
    'getCurrentThreadTaskHostContractVersion(): number',
    'isCurrentThreadHostRegistrationActive(registrationHigh: number, registrationLow: number): boolean',
    'reserveCurrentThreadHostRegistration(): BindingHostRegistration',
    'registerCurrentThreadTaskHost(registrationHigh: number, registrationLow: number, dispatch?: never): void',
    'registerTimerHost(registrationHigh: number, registrationLow: number, schedule: (id: number, ms: number) => Promise<void>, cancel: (id: number) => void): void',
    'unregisterCurrentThreadTaskHost(registrationHigh: number, registrationLow: number): void',
    'unregisterTimerHost(registrationHigh: number, registrationLow: number): void',
  ]) {
    if (!bindingDeclaration.includes(signature)) {
      failures.push(
        `${path.relative(REPO_ROOT, bindingDeclarationPath)}: missing generation-aware signature ${signature}`,
      );
    }
  }

  const declaration = fs.readFileSync(path.join(REPO_ROOT, THREADLESS_DECLARATION), 'utf8');
  if (
    !declaration.startsWith(
      "import type * as RolldownBinding from './rolldown-binding.wasip1.cjs';\n",
    )
  ) {
    failures.push(
      `${THREADLESS_DECLARATION}: must derive binding types from the threadless wasip1 declaration`,
    );
  }

  const wasmPath = path.join(
    REPO_ROOT,
    'packages/rolldown/src/rolldown-binding.wasm32-wasip1.wasm',
  );
  const wasmModule = new WebAssembly.Module(fs.readFileSync(wasmPath));
  const importDescriptors = WebAssembly.Module.imports(wasmModule);
  const memoryImports = importDescriptors.filter(({ kind }) => kind === 'memory');
  const unsupportedImports = importDescriptors.filter(
    ({ kind }) => kind !== 'function' && kind !== 'memory',
  );
  if (
    memoryImports.length !== 1 ||
    memoryImports[0].module !== 'env' ||
    memoryImports[0].name !== 'memory'
  ) {
    failures.push(`${wasmPath}: must import exactly one memory as env.memory`);
  } else if (unsupportedImports.length > 0) {
    failures.push(
      `${wasmPath}: minimum-memory probe does not support imports ${unsupportedImports
        .map(({ module, name, kind }) => `${module}.${name}:${kind}`)
        .join(', ')}`,
    );
  } else {
    const importObject = {};
    for (const descriptor of importDescriptors) {
      importObject[descriptor.module] ??= {};
      if (descriptor.kind === 'function') {
        importObject[descriptor.module][descriptor.name] = () => 0;
      }
    }
    const canInstantiateWithPages = (initial) => {
      importObject.env.memory = new WebAssembly.Memory({
        initial,
        maximum: configuredMaximumMemory,
      });
      try {
        new WebAssembly.Instance(wasmModule, importObject);
        return true;
      } catch (error) {
        if (error instanceof WebAssembly.LinkError && /memory import/.test(error.message)) {
          return false;
        }
        throw error;
      }
    };
    if (!canInstantiateWithPages(configuredInitialMemory)) {
      failures.push(
        `${wasmPath}: configured initial memory (${configuredInitialMemory} pages) cannot satisfy env.memory`,
      );
    } else {
      let lower = 1;
      let upper = configuredInitialMemory;
      while (lower < upper) {
        const candidate = Math.floor((lower + upper) / 2);
        if (canInstantiateWithPages(candidate)) {
          upper = candidate;
        } else {
          lower = candidate + 1;
        }
      }
      importedMinimumMemory = lower;
    }
  }
}

for (const rel of LOADERS) {
  const abs = resolveLoader(rel);
  let source;
  try {
    source = fs.readFileSync(abs, 'utf8');
  } catch {
    failures.push(`${rel}: file not found`);
    continue;
  }

  const code = stripComments(source);

  for (const pattern of FORBIDDEN) {
    if (pattern.test(code)) {
      failures.push(`${rel}: contains forbidden thread marker ${pattern}`);
    }
  }
  for (const removedMarker of [
    'cancelCurrentThreadRuntimeTaskDispatch',
    'driveCurrentThreadRuntimeTasks',
    '__dispatchCurrentThreadRuntimeTasks',
    '__pendingCurrentThreadTurns',
  ]) {
    if (source.includes(removedMarker)) {
      failures.push(`${rel}: contains removed CurrentThread task-host marker ${removedMarker}`);
    }
  }
  for (const requiredHostExport of [
    'getCurrentThreadTaskHostContractVersion',
    'registerCurrentThreadTaskHost',
    'unregisterCurrentThreadTaskHost',
  ]) {
    if (!source.includes(requiredHostExport)) {
      failures.push(`${rel}: missing CurrentThread task-host ABI ${requiredHostExport}`);
    }
  }

  if (rel.endsWith('.wasip1.cjs') || rel.endsWith('.wasip1-browser.js')) {
    for (const [label, pattern] of [
      ['bootstrap start', /ROLLDOWN_CURRENT_THREAD_HOST_BOOTSTRAP_START/],
      [
        'zero-argument contract-version call',
        /Reflect\.apply\(\s*__getCurrentThreadTaskHostContractVersion,\s*__rolldownBinding,\s*\[\],?\s*\)/,
      ],
      ['contract version 4 validation', /__taskHostContractVersion !== 4/],
      [
        'zero-argument host reservation',
        /Reflect\.apply\(\s*__reserveCurrentThreadHostRegistration,\s*__rolldownBinding,\s*\[\],?\s*\)/,
      ],
      [
        'reserved task-host registration',
        /Reflect\.apply\(__registerCurrentThreadTaskHost, __rolldownBinding, \[\s*__taskHostRegistration\.high,\s*__taskHostRegistration\.low,?\s*\]\)/,
      ],
      ['task-host registration validation', /__readHostRegistration\([\s\S]*?'task'/],
      [
        'task-host liveness validation',
        /__assertHostRegistrationActive\(__taskHostRegistration, 'task'\)/,
      ],
      ['timer-host registration', /Reflect\.apply\(__registerTimerHost, __rolldownBinding, \[/],
    ]) {
      if (!pattern.test(source)) {
        failures.push(`${rel}: missing generated CurrentThread host bootstrap ${label}`);
      }
    }
    if (rel.endsWith('.wasip1-browser.js')) {
      const taskUnregisterPattern =
        /Reflect\.apply\(__binding\.unregisterCurrentThreadTaskHost, __binding, \[\s*__browserTaskHostRegistration\.high,\s*__browserTaskHostRegistration\.low,\s*\]\)/;
      const taskUnregister = source.search(taskUnregisterPattern);
      const contextDestroy = source.search(
        /__cleanup\(\s*\(\) => __destroyEmnapiContext\(\),\s*['"]Threadless browser context cleanup failed['"],?\s*\)/,
      );
      if (taskUnregister === -1) {
        failures.push(
          `${rel}: missing exact CurrentThread task-host unregister with the captured high/low token`,
        );
      }
      if (contextDestroy === -1 || (taskUnregister !== -1 && taskUnregister > contextDestroy)) {
        failures.push(
          `${rel}: CurrentThread task host must unregister before browser context destruction`,
        );
      }
    }
    if (!code.includes(`initial: ${configuredInitialMemory},`)) {
      failures.push(
        `${rel}: generated initial memory does not match package config (${configuredInitialMemory} pages)`,
      );
    }
    if (!code.includes(`maximum: ${configuredMaximumMemory},`)) {
      failures.push(
        `${rel}: generated maximum memory does not match package config (${configuredMaximumMemory} pages)`,
      );
    }
  } else {
    for (const required of [
      'Reflect.apply(__getContractVersion, __binding, [])',
      '__actualVersion !== 4',
      'but version 4 is required',
      'Reflect.apply(__reserve, __binding, [])',
      'Reflect.apply(__register, __binding, __registration)',
      'Reflect.apply(__unregister, __binding, __registration)',
    ]) {
      if (!source.includes(required)) {
        failures.push(`${rel}: missing managed CurrentThread task-host marker ${required}`);
      }
    }
    const finishCallStart = source.indexOf('const __finishCall = (');
    const finishCallEnd = source.indexOf('const __wrapOutputDescriptor = (', finishCallStart);
    const finishCall =
      finishCallStart >= 0 && finishCallEnd > finishCallStart
        ? source.slice(finishCallStart, finishCallEnd)
        : '';
    const closedCheck = finishCall.indexOf(
      "Reflect.get(__closeOwner, 'closed', __closeOwner) === true",
    );
    const releaseAfterRejectedClose = finishCall.indexOf(
      '__releaseBindingObject(__closeOwner)',
      closedCheck,
    );
    if (
      closedCheck < 0 ||
      releaseAfterRejectedClose < closedCheck ||
      finishCall.match(/__releaseBindingObject\(__closeOwner\)/g)?.length !== 2
    ) {
      failures.push(
        `${rel}: managed close must release exactly once on success and after a terminal rejected close`,
      );
    }
    if (!code.includes(`initialPages: ${configuredInitialMemory},`)) {
      failures.push(
        `${rel}: generated initial memory does not match package config (${configuredInitialMemory} pages)`,
      );
    }
    if (!code.includes(`maximumPages: ${configuredMaximumMemory},`)) {
      failures.push(
        `${rel}: generated maximum memory does not match package config (${configuredMaximumMemory} pages)`,
      );
    }
  }

  // The async work pool must be disabled. Collect EVERY executable
  // `asyncWorkPoolSize: <n>` occurrence: require at least one literal 0 and
  // reject any non-zero value (a presence-only check let `asyncWorkPoolSize: 4`
  // pass as long as a `: 0` appeared anywhere, including in a comment).
  const sizes = [...code.matchAll(/asyncWorkPoolSize:\s*(\d+)\b/g)].map((m) => Number(m[1]));
  if (sizes.length === 0) {
    failures.push(`${rel}: missing required option asyncWorkPoolSize: 0`);
  } else {
    const nonZero = sizes.filter((n) => n !== 0);
    if (nonZero.length > 0) {
      failures.push(
        `${rel}: non-zero asyncWorkPoolSize present (${nonZero.join(', ')}) — async work pool must be disabled (0)`,
      );
    }
  }
}

if (failures.length > 0) {
  console.error('Single-thread WASI loaders are NOT threadless:');
  console.error();
  for (const f of failures) {
    console.error(`  ${f}`);
  }
  console.error();
  console.error(
    'The non-threaded build must emit loaders with no Worker creation, no shared memory, and asyncWorkPoolSize: 0. ' +
      'Check the @napi-rs/cli version / patch and the `hasThreads` target resolution.',
  );
  process.exit(1);
}

console.log(
  `OK: single-thread WASI loaders are threadless, host-integrated, and use ${configuredInitialMemory} initial pages${importedMinimumMemory === undefined ? '' : ` for a ${importedMinimumMemory}-page Wasm import minimum`} — checked ${LOADERS.join(', ')}.`,
);
